import { PrismaClient, AdviceCategory, ContentSource } from '@prisma/client';
const prisma = new PrismaClient();

export async function seedToddlerAdviceCards() {
  console.log('Seeding toddler advice cards (months 13-24)...');
  const cards = [
    { stageKey: 'born_month_13', category: 'DEVELOPMENT' as AdviceCategory, priority: 92, title: 'Celebrating First Steps Confidence', summary: 'As walking becomes more steady, your toddler enters a new world of exploration and independence.', content: 'Between 13 and 15 months, most toddlers transition from wobbly first steps to confident walking. This milestone unlocks a new perspective on their world — and yours. Encourage practice by creating safe open spaces free of sharp edges and hard corners. Avoid baby walkers, which can delay motor development and pose safety risks. Celebrate each attempt; your encouragement fuels their motivation to keep trying.', source: 'DEVELOPMENT' as ContentSource, tags: ['first steps', 'walking confidence', 'gross motor', 'toddler mobility'] },
    { stageKey: 'born_month_13', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Saying Goodbye to the Bottle', summary: 'Transitioning from bottle to cup is an important developmental step for oral health and independence.', content: 'Pediatric dentists recommend phasing out bottles between 12 and 18 months to prevent tooth decay and support proper oral development. Start by replacing one bottle feed at a time with a sippy cup or open cup — the midday bottle is often easiest to drop first. Offer water between meals and reserve milk for meal and snack times. Some toddlers resist at first; consistency and modeling cup drinking yourself go a long way. Avoid letting your child fall asleep with a bottle, as pooled milk can cause serious dental issues.', source: 'DEVELOPMENT' as ContentSource, tags: ['bottle weaning', 'cup transition', 'oral health', 'toddler feeding'] },
    { stageKey: 'born_month_13', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Separation Anxiety and Bedtime', summary: 'As separation anxiety peaks around 13 months, bedtime can become more challenging for both of you.', content: 'This developmental surge means your toddler now understands you exist when out of sight — and they would much rather you stayed. The result can be tearful bedtimes and more frequent night wakings. Maintain a calm, consistent routine without reverting to new sleep crutches. A transitional object like a small lovey or blanket can offer comfort. Keep goodbyes brief but warm; lingering can increase distress. Remember this phase signals healthy attachment and will pass with consistency.', source: 'DEVELOPMENT' as ContentSource, tags: ['separation anxiety', 'bedtime struggles', 'toddler sleep', 'attachment', 'sleep routine'] },
    { stageKey: 'born_month_13', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 93, title: 'Climbing Safety in Your Home', summary: 'New climbing skills bring new safety considerations that every parent should address.', content: 'Around 13 months, many toddlers discover the joy of climbing — onto furniture, up stairs, and anywhere their new leg strength allows. This is excellent for motor development but requires proactive safety measures. Secure bookshelves and dressers to the wall with anti-tip brackets. Install safety gates at the top and bottom of stairs. Keep chairs and step stools away from counters and windows. Supervise climbing play rather than prohibiting it entirely; consider a small indoor climbing structure to satisfy this developmental urge safely.', source: 'CLINICAL' as ContentSource, tags: ['climbing safety', 'toddlerproofing', 'furniture anchors', 'stair gates', 'home safety'] },
    { stageKey: 'born_month_13', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Early Word Games and Vocabulary Building', summary: 'Simple word games tap into your toddler\'s growing language skills and deepen your connection.', content: 'At 13 months, toddlers typically have 1 to 5 words and understand many more. Turn daily routines into language-rich moments by narrating your actions and naming objects. Play simple games like "Where is your nose?" or point to pictures in books and name them together. Animal sounds are especially engaging at this age. Follow your toddler\'s gaze and name what they are looking at — this joint attention is powerful for vocabulary growth. Resist quizzing; instead model language naturally throughout the day.', source: 'DEVELOPMENT' as ContentSource, tags: ['language development', 'word games', 'vocabulary', 'early communication', 'joint attention'] },
    { stageKey: 'born_month_13', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'The One-Year Mark: Reflecting on Your Journey', summary: 'Reaching the one-year milestone is an opportunity to honor your growth as a parent.', content: 'The first birthday marks not just your child\'s growth but your transformation as a parent. You have navigated sleepless nights, feeding challenges, and countless worries — all while learning who your child is becoming. Take a moment to reflect on what you have learned about yourself. Many parents find the toddler phase brings new emotional complexity as their baby becomes more independent. Connect with other parents of toddlers; shared experience reduces isolation. Your resilience and love have brought you both to this milestone.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent reflection', 'one year milestone', 'parent wellbeing', 'parenting journey', 'self-care'] },
    { stageKey: 'born_month_14', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'From First Steps to Running', summary: 'Around 14 months, many toddlers begin to pick up speed, transitioning from walking to running.', content: 'Running emerges as balance and confidence improve, typically between 14 and 18 months. Your toddler may look unsteady with their arms held high for balance — this wide-based, high-guard running stance is developmentally appropriate. Falls are frequent and normal; your calm response teaches resilience. Provide soft, safe surfaces for practice indoors and out. Barefoot time on varied textures helps strengthen foot muscles and improves balance. This explosion of mobility often brings a joyful, almost giddy energy to your toddler\'s day.', source: 'DEVELOPMENT' as ContentSource, tags: ['running milestones', 'gross motor', 'toddler mobility', 'balance development'] },
    { stageKey: 'born_month_14', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Spoon Skills and Self-Feeding Practice', summary: 'Messy self-feeding with a spoon is building independence, motor skills, and a healthy relationship with food.', content: 'At 14 months, spoon use is improving but still messy — and that mess is exactly what learning looks like. Offer thick, scoopable foods like yogurt, oatmeal, or mashed potatoes that cling to the spoon. Provide a pre-loaded spoon for your toddler to grasp and guide to their mouth. Resist the urge to take over when things get messy; autonomy at meals supports long-term healthy eating habits. Keep a second spoon for yourself to ensure some food actually gets eaten. A wipe-clean mat under the high chair saves your floor and your sanity.', source: 'DEVELOPMENT' as ContentSource, tags: ['self-feeding', 'spoon skills', 'toddler independence', 'mealtime learning', 'fine motor'] },
    { stageKey: 'born_month_14', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Stacking Blocks and Building Play', summary: 'Stacking two to three blocks is a key milestone that builds fine motor skills and spatial reasoning.', content: 'Around 14 months, toddlers can typically stack two to three blocks, a skill requiring hand-eye coordination, precision grip, and an understanding of balance. Start with larger blocks that are easier to manipulate and less frustrating. Building together and then knocking down — "boom!" — is often the most thrilling part for your toddler. This destruction phase is actually constructive: it teaches cause and effect. Offer a variety of stacking materials like soft blocks, nesting cups, and even empty food containers. Celebrate the tower, then celebrate the crash with equal enthusiasm.', source: 'DEVELOPMENT' as ContentSource, tags: ['block play', 'stacking', 'fine motor skills', 'spatial reasoning', 'cause and effect'] },
    { stageKey: 'born_month_14', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Understanding and Easing Stranger Anxiety', summary: 'Stranger anxiety can intensify around 14 months as your toddler\'s memory and attachment systems develop.', content: 'Stranger anxiety reflects a cognitive leap: your toddler now clearly distinguishes familiar people from unfamiliar ones and has developed strong preferences for their attachment figures. Rather than forcing interaction, give your toddler time to warm up from the safety of your lap. Ask visitors to approach slowly, avoid intense eye contact initially, and let your child initiate interaction. Narrate what is happening: "This is Aunt Sarah. She is Mommy\'s sister." Never dismiss their fear as silly; validating their feelings builds emotional security. This phase typically eases by 18 to 24 months.', source: 'DEVELOPMENT' as ContentSource, tags: ['stranger anxiety', 'social development', 'attachment', 'emotional security', 'toddler fears'] },
    { stageKey: 'born_month_14', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 89, title: 'Your Toddler\'s First Tantrums', summary: 'Tantrums typically begin around 14 months and are a normal, developmentally expected expression of frustration.', content: 'The emergence of tantrums catches many parents off guard. Your toddler has strong desires and opinions but lacks the language skills and emotional regulation to express them appropriately. Tantrums are not manipulation at this age — they are genuine overwhelm. When a tantrum happens, ensure safety, stay nearby, and offer calm presence without trying to reason through it. After the storm passes, offer comfort and a simple label: "You were really frustrated." Avoid giving in to the tantrum\'s demand, but do acknowledge the feeling. Your calm co-regulation is literally building their brain\'s capacity for self-regulation over time.', source: 'DEVELOPMENT' as ContentSource, tags: ['tantrums', 'emotional regulation', 'toddler behavior', 'co-regulation', 'parent patience'] },
    { stageKey: 'born_month_14', category: 'SLEEP' as AdviceCategory, priority: 91, title: 'Maintaining Sleep Routines Through New Mobility', summary: 'Newfound mobility can disrupt sleep as your toddler practices skills in the crib and resists winding down.', content: 'When toddlers acquire new motor skills, the urge to practice can override the drive to sleep. You may find your 14-month-old standing in the crib, walking along the rails, or even climbing. Ensure the crib mattress is at the lowest setting as soon as your toddler can stand. Keep the pre-nap and bedtime routines calm and consistent, even when your toddler resists. A brief period of crib practice followed by settling is normal; if your toddler is not distressed, give them space to work through it. Increased daytime physical activity helps satisfy the movement drive and supports better sleep.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler sleep', 'crib safety', 'motor milestones', 'bedtime resistance', 'sleep routines'] },
    { stageKey: 'born_month_15', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Following Simple Commands', summary: 'Following simple one-step directions represents a major leap in receptive language and cognitive processing.', content: 'Around 15 months, most toddlers can follow simple one-step commands like "bring me the ball" or "come here" — especially when paired with gestures. This milestone reflects growing receptive language, working memory, and the ability to connect words with actions. Keep directions short and specific: "Put the book on the table" works better than "Clean up your toys." Pair words with pointing to support comprehension. Celebrate compliance warmly; your positive reaction reinforces cooperation. If your toddler does not respond, check for hearing issues and consider whether they are simply absorbed in play rather than ignoring you.', source: 'DEVELOPMENT' as ContentSource, tags: ['following directions', 'receptive language', 'cognitive development', 'toddler communication', 'listening skills'] },
    { stageKey: 'born_month_15', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Body Part Games and Songs', summary: 'Learning body parts through playful songs and games builds vocabulary and self-awareness.', content: 'Body part identification typically emerges between 13 and 18 months. Games like "Where is your nose?" and songs like "Head, Shoulders, Knees, and Toes" make this learning joyful. Start with visible body parts like tummy, feet, and hands before moving to facial features. Use bath time, dressing, and mirror play as natural opportunities for body part naming. Point to your own body parts and your toddler\'s to reinforce the concept. This learning builds the foundation for later self-care skills like dressing and hygiene. Keep it playful — your laughter and engagement are the best motivators.', source: 'DEVELOPMENT' as ContentSource, tags: ['body parts', 'language games', 'self-awareness', 'toddler songs', 'early learning'] },
    { stageKey: 'born_month_15', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Self-Feeding Success at 15 Months', summary: 'Your toddler\'s drive for independence at the table is a healthy sign worth nurturing.', content: 'By 15 months, most toddlers can feed themselves with a spoon with decreasing spillage and are increasingly interested in doing things themselves. Offer appropriately sized utensils with easy-grip handles. Expect mess — a splat mat under the chair and a bib with a catch pocket reduce cleanup. Provide choices between two acceptable options: "Would you like the red cup or the blue cup?" This satisfies the need for control within boundaries you set. Eat together as a family whenever possible; toddlers eat more variety when they see others enjoying those foods. End the meal when your toddler signals they are done rather than pushing for "one more bite."', source: 'DEVELOPMENT' as ContentSource, tags: ['self-feeding', 'toddler nutrition', 'mealtime independence', 'family meals', 'healthy eating'] },
    { stageKey: 'born_month_15', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Climbing Stairs Safely at 15 Months', summary: 'Stair climbing is a key gross motor milestone that requires both opportunity for practice and safety precautions.', content: 'Around 15 months, toddlers typically begin climbing stairs with help, often crawling up on hands and knees while holding a parent\'s hand. This builds leg strength, coordination, and confidence. Supervise stair practice daily, teaching your toddler to go up on hands and knees and come down backward on their belly — the safest method for early walkers. Install hardware-mounted safety gates at top and bottom of stairs; pressure-mounted gates are not reliable for the top of stairs. Never leave a toddler unattended near stairs, even for a moment. The goal is to teach safe stair navigation while preventing unsupervised access during this high-risk window.', source: 'CLINICAL' as ContentSource, tags: ['stair safety', 'gross motor milestones', 'toddler safety', 'climbing development', 'home safety'] },
    { stageKey: 'born_month_15', category: 'SLEEP' as AdviceCategory, priority: 88, title: 'Nap Schedule Refinement at 15 Months', summary: 'Fine-tuning the nap schedule helps ensure your toddler gets the restorative sleep their growing brain needs.', content: 'By 15 months, most toddlers have settled into a two-nap or transitioning-to-one-nap schedule. Watch for sleepy cues rather than watching the clock exclusively — eye rubbing, decreased activity, and crankiness are reliable signals. A morning nap that becomes too short or is resisted may signal readiness to transition to one midday nap. If you are in transition, offer quiet rest time even when your toddler does not sleep. The total sleep need at this age is 11 to 14 hours in a 24-hour period. An overtired toddler actually has more difficulty falling and staying asleep, so do not push wake windows too long.', source: 'DEVELOPMENT' as ContentSource, tags: ['nap schedule', 'toddler sleep needs', 'nap transition', 'sleep cues', 'healthy sleep'] },
    { stageKey: 'born_month_15', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 83, title: 'Finding Moments of Calm Amid Toddler Chaos', summary: 'Intentionally carving small moments of calm into your day protects your mental health and your parenting.', content: 'Parenting a 15-month-old is physically and emotionally demanding. Your toddler\'s mobility, curiosity, and limited impulse control mean constant vigilance. Small, intentional self-care moments — a five-minute breathing exercise, a hot drink while your toddler plays nearby, a brief phone call with a friend — can reset your nervous system. Consider trading childcare with another parent for even a short break. The cumulative effect of micro-breaks is more sustainable than waiting for the elusive full day off. Remember that meeting your own basic needs is not selfish; it is what allows you to meet your child\'s needs with patience and presence.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent self-care', 'stress management', 'parent wellbeing', 'mental health', 'mindful parenting'] },
    { stageKey: 'born_month_16', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Walking Backward: A Motor Planning Milestone', summary: 'Walking backward emerges around 16 months and reflects growing motor planning and spatial awareness.', content: 'Walking backward requires more advanced motor planning than forward walking — your toddler must coordinate movement in a direction they cannot see. This skill typically emerges between 15 and 18 months. Encourage practice with push-pull toys designed for backward pulling or simple games like backing up to sit on a small stool. Walking backward builds body awareness, balance, and the coordination needed for later skills like running and jumping. Celebrate this quirky milestone when you see it; your toddler may look proud and surprised at their own ability. Provide clear, safe space for backward exploration away from furniture edges and stairs.', source: 'DEVELOPMENT' as ContentSource, tags: ['walking backward', 'motor planning', 'gross motor', 'spatial awareness', 'toddler milestones'] },
    { stageKey: 'born_month_16', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Imitation Play and Household Helpers', summary: 'Your toddler\'s drive to imitate household tasks is a powerful learning opportunity you can harness.', content: 'Around 16 months, toddlers begin eagerly imitating household activities — sweeping, wiping, stirring, and putting items in and out of containers. This imitation is how they learn about adult roles and practice motor skills. Provide child-sized versions of everyday tools: a small broom, a play kitchen with pots and spoons, a dusting cloth. Involve your toddler in simple real tasks like putting socks in the laundry basket or wiping their high chair tray. The process matters far more than the result; resist correcting their efforts. This early participation lays the groundwork for later helpfulness and life skills.', source: 'DEVELOPMENT' as ContentSource, tags: ['imitation play', 'household helpers', 'toddler activities', 'life skills', 'pretend play'] },
    { stageKey: 'born_month_16', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 87, title: 'Navigating the Peak of Picky Eating', summary: 'Picky eating often peaks around 16 months as growth slows and autonomy drives food refusal.', content: 'Around 16 months, many toddlers enter a peak picky eating phase. This is biologically normal: growth has slowed from the rapid first year, so appetite naturally decreases. Combine that with a fierce drive for autonomy and you get a toddler who rejects yesterday\'s favorite food. Your job is to offer a variety of healthy foods at regular meal and snack times; your toddler\'s job is to decide what and how much to eat from what you offer. Include at least one accepted food at each meal alongside new or less-preferred foods. Avoid short-order cooking — making a separate meal teaches your toddler that refusal leads to preferred alternatives. Most picky eating phases resolve with consistent, low-pressure exposure to variety.', source: 'DEVELOPMENT' as ContentSource, tags: ['picky eating', 'toddler nutrition', 'feeding challenges', 'division of responsibility', 'food exposure'] },
    { stageKey: 'born_month_16', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Solidifying the One-Nap Schedule', summary: 'A consistent one-nap schedule supports optimal sleep quality and a smoother daily rhythm.', content: 'By 16 months, most toddlers have transitioned to one midday nap, typically lasting 1.5 to 3 hours. A predictable nap time — usually starting between 12:00 and 1:00 PM — helps regulate your toddler\'s body clock. Protect this nap; it is essential for memory consolidation, emotional regulation, and physical growth. If your toddler has transitioned but naps are short or inconsistent, consider whether the wake window before nap is appropriate — roughly 5 to 6 hours at this age. An earlier bedtime on days when the nap is short prevents overtiredness from accumulating. A consistent pre-nap wind-down routine signals to your toddler\'s brain that sleep is coming.', source: 'DEVELOPMENT' as ContentSource, tags: ['one nap schedule', 'toddler sleep', 'nap consolidation', 'sleep hygiene', 'daily rhythm'] },
    { stageKey: 'born_month_16', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 85, title: '16-Month Growth and Development Overview', summary: 'Understanding the growth patterns and health priorities at 16 months helps you support your toddler\'s wellbeing.', content: 'At 16 months, growth continues at a steady but slower pace than the first year. Your toddler may gain 3 to 5 pounds and grow 3 to 4 inches during the entire second year. Head circumference growth slows but continues steadily — a key neurological health indicator. Appetite fluctuations are normal and typically reflect growth spurts and plateaus rather than a problem. Ensure your toddler is up to date on immunizations and receiving regular well-child care. Report any loss of previously acquired skills, as developmental regression warrants prompt evaluation. Trust your instincts — you know your child best.', source: 'CLINICAL' as ContentSource, tags: ['toddler growth', 'development monitoring', 'well-child care', 'growth patterns', 'toddler health'] },
    { stageKey: 'born_month_16', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 86, title: 'Staying Patient Through Mealtime Struggles', summary: 'Mealtime battles can drain your patience; shifting your mindset protects your wellbeing and your relationship.', content: 'Repeated food refusal can feel personal and triggering, especially when you have put effort into preparing a meal. Remind yourself that picky eating at this age is developmentally normal and not a reflection of your parenting. Lower the stakes: a toddler who eats a few bites of one food at a meal is doing fine. The Division of Responsibility framework — you decide what, when, and where; your child decides whether and how much — relieves you of the pressure to make your child eat. If mealtime stress is significantly affecting your wellbeing, consider consulting a pediatric dietitian for individualized support.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent patience', 'mealtime stress', 'feeding struggles', 'parent wellbeing', 'self-compassion'] },
    { stageKey: 'born_month_17', category: 'DEVELOPMENT' as AdviceCategory, priority: 93, title: 'When Toddlers Bite and Hit', summary: 'Biting and hitting are common at 17 months and stem from frustration and limited communication, not malice.', content: 'Aggressive behaviors like biting and hitting peak in the second year and are developmentally normal, not a sign of a "bad" child or bad parenting. Your toddler lacks the words and impulse control to express frustration, excitement, or overwhelm any other way. Respond calmly and immediately: "Biting hurts. I won\'t let you bite." Then shift attention to the hurt child, not the aggressor — long lectures are lost on a toddler. Identify patterns: is it happening when hungry, tired, or overstimulated? Prevention through proactive snack times, adequate sleep, and calm environments is more effective than punishment. Teach a simple alternative like stomping feet or saying "mad" as language develops.', source: 'DEVELOPMENT' as ContentSource, tags: ['biting', 'hitting', 'toddler aggression', 'behavior guidance', 'emotional development'] },
    { stageKey: 'born_month_17', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 83, title: 'Healthy Snacks for Active Toddlers', summary: 'Strategic snacks fuel your busy 17-month-old while supporting healthy eating patterns throughout the day.', content: 'Active toddlers burn energy quickly and have small stomachs, making nutritious snacks an important part of the daily eating pattern. Aim for two to three scheduled snacks between meals rather than all-day grazing, which can undermine mealtime appetite. Pair a protein or fat with a carbohydrate for staying power: apple slices with cheese, whole-grain crackers with hummus, yogurt with berries. Cut foods into safe, manageable pieces to prevent choking. Offer water between meals rather than milk or juice. Keep a few go-to snack options prepped in the fridge for hungry-toddler emergencies.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler snacks', 'healthy eating', 'toddler nutrition', 'meal planning', 'snack ideas'] },
    { stageKey: 'born_month_17', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 85, title: 'Dressing Games That Build Independence', summary: 'Playful dressing practice turns a daily power struggle into a skill-building opportunity.', content: 'Around 17 months, toddlers begin helping with dressing — pushing arms through sleeves, pulling off socks, and attempting to put on shoes. Frame dressing as a game: "Can you poke your hand through this tunnel?" or "Let\'s find where your foot lives!" Offer limited choices between two outfits to satisfy the need for autonomy. Allow extra time for dressing without rushing; frustration increases when toddlers feel hurried. Start with easy wins like pulling up pants from their knees or removing an unzipped jacket. Celebrate effort, not just success.', source: 'DEVELOPMENT' as ContentSource, tags: ['dressing skills', 'toddler independence', 'self-care', 'fine motor', 'playful routines'] },
    { stageKey: 'born_month_17', category: 'DEVELOPMENT' as AdviceCategory, priority: 89, title: 'The Word Explosion Around 17 Months', summary: 'Vocabulary typically grows from a handful of words toward 10 to 20 words around this age.', content: 'Around 17 months, many toddlers experience a noticeable acceleration in expressive language. Your child may go from 5 words to 15 or more in a matter of weeks. They understand far more than they can say — receptive language typically outpaces expressive language by a wide margin at this age. Respond to and expand your toddler\'s words: when they say "ball," you can reply, "Yes, the red ball is rolling!" Read together daily, pointing to and naming pictures. Limit background noise from screens, which can interfere with language processing. If your toddler has fewer than 5 words by 18 months, discuss with your pediatrician.', source: 'DEVELOPMENT' as ContentSource, tags: ['language explosion', 'vocabulary growth', 'expressive language', 'early words', 'language development'] },
    { stageKey: 'born_month_17', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 88, title: 'Managing the Independence Battles', summary: 'The toddler drive for autonomy can exhaust even the most patient parent; strategies for navigating this phase.', content: 'Seventeen months brings intense independence-seeking alongside limited competence. When every transition becomes a battle, step back and ask: where can I safely offer more autonomy? Choices about socks, snack order, or which book to read cost you nothing but mean everything to your toddler. Save your firm limits for health and safety issues. Use routines and predictability to reduce battles — toddlers feel more secure and cooperative when they know what to expect. Remember that this push for independence is exactly what healthy development looks like. Your toddler is not giving you a hard time; they are having a hard time regulating their own intense drive.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler independence', 'power struggles', 'parent patience', 'behavior guidance', 'autonomy support'] },
    { stageKey: 'born_month_17', category: 'SLEEP' as AdviceCategory, priority: 87, title: 'How Motor Milestones Disrupt Sleep', summary: 'New physical skills like running and climbing can temporarily disrupt sleep as your toddler\'s brain processes and practices.', content: 'Sleep disruptions frequently accompany major motor milestones. When your 17-month-old masters running or a new climbing skill, their brain may prioritize practicing that skill over settling for sleep. You might find them running laps in the crib or practicing new moves at bedtime. Ensure the sleep environment is safe — crib mattress at the lowest setting, no bumpers. Increased daytime physical activity, especially outdoor time, helps satisfy the movement drive. Maintain your consistent bedtime routine even through resistance. These disruptions typically resolve within one to two weeks as the novelty of the new skill wears off.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep disruption', 'motor milestones', 'crib safety', 'bedtime resistance', 'toddler sleep'] },
    { stageKey: 'born_month_18', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 96, title: 'The 18-Month Well-Child Visit', summary: 'The 18-month checkup is a comprehensive assessment of growth, development, and health.', content: 'The 18-month well-child visit is one of the most important checkups of the toddler period. Your pediatrician will measure growth parameters, assess developmental milestones, and screen for autism with the M-CHAT questionnaire. This visit typically includes immunizations, so plan for possible fussiness afterward. Bring your list of questions — about speech, behavior, sleep, or feeding — as the 18-month visit is an ideal time to address concerns. Be honest about challenges; your pediatrician has heard it all and can connect you with appropriate resources. The 18-month visit is also when many pediatricians discuss toilet learning readiness and dental care routines.', source: 'CLINICAL' as ContentSource, tags: ['18 month checkup', 'well-child visit', 'developmental screening', 'immunizations', 'toddler health'] },
    { stageKey: 'born_month_18', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 94, title: 'Understanding the M-CHAT Autism Screening', summary: 'The M-CHAT screening at 18 months is a routine, evidence-based tool to identify children who may benefit from early intervention.', content: 'The Modified Checklist for Autism in Toddlers (M-CHAT) is a standard screening tool administered at the 18-month visit. It consists of 20 yes-or-no questions about your child\'s social communication and behavior. A "fails" screen does not mean your child has autism — it indicates a need for further evaluation, and many children who fail go on to have typical development. Conversely, the screen can miss some children, so continue to trust your observations. Early signs may include limited eye contact, not responding to name, reduced pointing or showing objects, and limited pretend play. Early intervention is highly effective when indicated, so engage with the screening process openly and honestly.', source: 'CLINICAL' as ContentSource, tags: ['M-CHAT', 'autism screening', 'developmental screening', 'early intervention', '18 month checkup'] },
    { stageKey: 'born_month_18', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Symbolic Play and Language Development', summary: 'As symbolic play emerges around 18 months, you can watch your toddler\'s imagination and language skills grow together.', content: 'Symbolic play — using one object to represent another, like a block as a phone — marks a major cognitive leap around 18 months. This ability to hold mental representations parallels the language explosion happening at the same time. Provide simple props: a play phone, a doll with a bottle, a toy car, a few kitchen items. Join their play without directing it; let your toddler lead and follow their imagination. Narrate what you see: "You are feeding the baby. She looks hungry!" Symbolic play builds theory of mind, narrative thinking, and emotional processing.', source: 'DEVELOPMENT' as ContentSource, tags: ['symbolic play', 'pretend play', 'language development', 'cognitive development', 'imagination'] },
    { stageKey: 'born_month_18', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 85, title: 'Family Meals with Your 18-Month-Old', summary: 'Eating together as a family supports healthy eating habits, language development, and emotional connection.', content: 'By 18 months, your toddler can participate meaningfully in family meals. They can sit in a booster seat at the table, use a spoon and fork with increasing skill, and eat most of the same foods the family eats with appropriate modifications. Family meals are associated with better nutrition, lower rates of picky eating, and stronger language development through mealtime conversation. Turn off screens during meals to support mindful eating and connection. Model enjoyment of a variety of foods without pressuring your toddler to eat them. Keep mealtimes pleasant — a relaxed atmosphere supports better eating than tension or coercion. Even a 10-minute family breakfast counts.', source: 'DEVELOPMENT' as ContentSource, tags: ['family meals', 'toddler nutrition', 'mealtime connection', 'healthy eating habits', 'eating together'] },
    { stageKey: 'born_month_18', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Stair Climbing as Physical Play', summary: 'With supervision, practicing stairs builds strength, coordination, and confidence.', content: 'By 18 months, many toddlers can walk up stairs with one hand held, placing both feet on each step. Stair practice is excellent physical activity that builds leg strength, balance, and motor planning. Make it a game: count steps together, sing a climbing song, or place a favorite toy at the top as motivation. Teach safe techniques: going up with two hands on the rail or your hand, and coming down on their bottom or belly initially. Never rush stair practice or leave your toddler to navigate stairs independently. If you live in a single-story home, visit a park or community center with safe, low stairs for practice.', source: 'DEVELOPMENT' as ContentSource, tags: ['stair climbing', 'gross motor play', 'physical activity', 'toddler safety', 'motor development'] },
    { stageKey: 'born_month_18', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'Celebrating the 18-Month Milestone', summary: 'The halfway point of the second year is an opportunity to recognize how far both you and your toddler have come.', content: 'Eighteen months marks the midpoint of toddlerhood — a moment worth acknowledging. Your child has transformed from an infant into a walking, talking, opinionated small person with a rapidly expanding mind. Take time to notice and celebrate this growth, both in your child and in yourself. Look back at photos or videos from six months ago to appreciate how much has changed. Consider starting a simple tradition: a special outing, a letter to your child, or a small family celebration. The toddler phase is intense but fleeting. Pausing to mark milestones helps counterbalance the daily challenges with genuine appreciation.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent reflection', 'milestone celebration', 'toddlerhood', 'parent joy', 'family traditions'] },
    { stageKey: 'born_month_19', category: 'DEVELOPMENT' as AdviceCategory, priority: 89, title: 'Kicking, Throwing, and Gross Motor Mastery', summary: 'New ball skills at 19 months reflect improved coordination, balance, and whole-body motor planning.', content: 'Around 19 months, many toddlers can kick a ball forward without losing balance and throw a ball overhand, though aim is still developing. These skills represent sophisticated coordination between eyes, arms, and legs. Provide a variety of balls — soft, lightweight ones for indoor play and slightly larger ones for outdoor kicking games. Set up simple targets like a laundry basket for throwing practice. Avoid over-coaching; at this age, exploration and enjoyment matter more than technique. Ball play also builds social skills when done with parents or peers.', source: 'DEVELOPMENT' as ContentSource, tags: ['ball skills', 'kicking', 'throwing', 'gross motor', 'coordination development'] },
    { stageKey: 'born_month_19', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 86, title: 'Shape Sorting and Early Puzzle Play', summary: 'Beginning to sort shapes and complete simple puzzles marks growing spatial reasoning and problem-solving abilities.', content: 'Between 18 and 19 months, toddlers often show new interest in shape sorters and simple inset puzzles with large knobs. This reflects developing visual-spatial skills, hand-eye coordination, and the cognitive ability to match shapes. Start with a shape sorter featuring just two or three simple shapes before introducing more complex ones. Sit nearby to offer gentle guidance if frustration builds, but allow your toddler to experiment. Name the shapes as your toddler handles them. The satisfaction of placing the correct shape builds persistence and confidence.', source: 'DEVELOPMENT' as ContentSource, tags: ['shape sorting', 'puzzles', 'spatial reasoning', 'problem solving', 'fine motor play'] },
    { stageKey: 'born_month_19', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'Understanding and Preventing Tantrums', summary: 'At 19 months, tantrums are predictable responses to frustration; understanding their triggers allows for more effective prevention.', content: 'By 19 months, tantrums tend to increase in frequency and intensity as your toddler\'s desires outpace their abilities and communication skills. Common triggers include hunger, fatigue, overstimulation, transitions, and being told no. Prevention starts with meeting basic needs proactively: regular meals and snacks, consistent sleep, and manageable amounts of stimulation. Give warnings before transitions: "Two more minutes of play, then we go inside." Offer choices within limits to satisfy the need for control. When prevention fails — and it will — stay calm and present. Your regulated nervous system is the most powerful tool for helping your toddler return to calm.', source: 'DEVELOPMENT' as ContentSource, tags: ['tantrum management', 'emotional regulation', 'toddler behavior', 'prevention strategies', 'co-regulation'] },
    { stageKey: 'born_month_19', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 88, title: 'Staying Calm During Your Toddler\'s Tantrums', summary: 'Maintaining your own emotional regulation during your child\'s outburst is one of the hardest and most important parenting skills.', content: 'Your toddler\'s tantrum can trigger your own stress response — racing heart, frustration, even anger. This is normal and does not make you a bad parent. Prepare a personal strategy for tantrum moments: a deep breath, a grounding phrase like "This is not an emergency," or a physical anchor like pressing your feet into the floor. Remind yourself that your toddler\'s developing brain is genuinely overwhelmed, not manipulating you. If you feel yourself losing control, it is okay to ensure your child is safe and step away for a moment to regulate. Repair after your own dysregulation by offering a calm, simple apology. This models emotional recovery.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent regulation', 'tantrum response', 'emotional resilience', 'mindful parenting', 'self-regulation'] },
    { stageKey: 'born_month_19', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 84, title: 'Building a Positive Mealtime Environment', summary: 'The emotional climate of meals shapes your toddler\'s relationship with food more powerfully than any specific food rule.', content: 'Research consistently shows that the emotional tone of meals matters as much for healthy eating as the food served. Aim for a calm, connected atmosphere free of pressure, bargaining, or praise for eating. Avoid comments like "Just one more bite" or "Good job eating your broccoli," which can backfire over time. Instead, enjoy your own food and engage in pleasant conversation. Your toddler learns that mealtimes are about connection and enjoyment, not performance. If a meal goes poorly, let it go — the next meal is a fresh start.', source: 'DEVELOPMENT' as ContentSource, tags: ['mealtime environment', 'feeding relationship', 'positive eating', 'toddler nutrition', 'family meals'] },
    { stageKey: 'born_month_19', category: 'SLEEP' as AdviceCategory, priority: 92, title: 'Navigating Night Terrors vs. Nightmares', summary: 'Knowing the difference between night terrors and nightmares helps you respond appropriately and reduce parental anxiety.', content: 'Night terrors typically emerge between 18 months and 3 years and are distinctly different from nightmares. During a night terror, your child may scream, thrash, and appear awake but is actually in deep non-REM sleep and will not recognize you. Attempting to wake or comfort them can prolong the episode. Instead, ensure safety and wait nearby until it passes, usually within 5 to 20 minutes. Night terrors are benign and not emotionally distressing to the child, who will have no memory of them. They are often triggered by overtiredness. Nightmares, in contrast, occur during REM sleep and your child will seek and accept comfort. If night terrors are frequent, discuss them with your pediatrician.', source: 'GENERAL' as ContentSource, tags: ['night terrors', 'nightmares', 'toddler sleep disorders', 'sleep health', 'parental reassurance'] },
    { stageKey: 'born_month_20', category: 'DEVELOPMENT' as AdviceCategory, priority: 89, title: 'Understanding Possession and "Mine"', summary: 'The possessive phase at 20 months is a normal milestone in developing self-identity, not selfishness.', content: 'Around 20 months, "mine" becomes a favorite word as your toddler develops a sense of self separate from others. This possessiveness reflects an emerging understanding of ownership and personal identity — concepts that are cognitively sophisticated. Your toddler is not being selfish; they are figuring out where they end and others begin. Narrate and validate feelings while gently teaching sharing concepts: "That is your truck. Sam would like a turn when you are done." Model sharing and taking turns in your own interactions. Practice turn-taking with a timer for short, concrete intervals.', source: 'DEVELOPMENT' as ContentSource, tags: ['possession', 'mine phase', 'sharing', 'social development', 'self-identity'] },
    { stageKey: 'born_month_20', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Jumping Games for Growing Skills', summary: 'Jumping with both feet is an exciting 20-month milestone that you can support with simple, joyful games.', content: 'Many toddlers begin attempting two-footed jumps around 20 months, though some may not clear the ground at first. This skill requires significant leg strength, balance, and motor planning. Create jumping games: jump over a crack in the sidewalk, jump like a frog, or jump to reach bubbles. A small trampoline with a handle bar offers safe jumping practice. Floor markers or tape lines on the ground make excellent low-stakes jumping targets. Celebrate the attempt, not the height or distance. Jumping also provides proprioceptive input that can be calming for some toddlers. Ensure the jumping surface is safe and clear of obstacles.', source: 'DEVELOPMENT' as ContentSource, tags: ['jumping', 'gross motor play', 'physical activity', 'toddler games', 'motor milestones'] },
    { stageKey: 'born_month_20', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 85, title: 'Fork Skills and Utensil Progression', summary: 'Using a fork is a complex fine motor skill that develops with opportunity, patience, and plenty of practice.', content: 'Around 20 months, many toddlers show interest in using a fork, though spearing food requires more precision than spoon use. Offer toddler-sized forks with rounded tines and easy-grip handles. Start with soft, easy-to-spear foods like banana chunks, pasta, or soft-cooked vegetables. Pre-load the fork and hand it to your toddler, or guide their hand gently if they welcome help. Expect that fingers will still be the primary tool for much of the meal — this is normal and appropriate. Celebrate effort rather than success, and never force utensil use.', source: 'DEVELOPMENT' as ContentSource, tags: ['fork skills', 'utensil use', 'self-feeding', 'fine motor', 'mealtime independence'] },
    { stageKey: 'born_month_20', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'Introducing a New Sibling at 20 Months', summary: 'Adding a baby to the family when your first is 20 months old requires thoughtful preparation and realistic expectations.', content: 'The arrival of a new sibling is a major transition for a toddler who is still very much a baby themselves. Prepare your toddler by reading books about new babies, looking at their own baby photos, and talking about what babies do — cry, nurse, sleep. After the baby arrives, carve out protected one-on-one time with your toddler daily, even if just 10 minutes. Expect regression in sleep, toileting, or behavior; this is your toddler\'s way of expressing stress. Avoid blaming the baby for limitations: instead of "I can\'t pick you up because I am feeding the baby," try "My hands are busy right now. I will pick you up in five minutes."', source: 'DEVELOPMENT' as ContentSource, tags: ['new sibling', 'sibling adjustment', 'toddler transition', 'family changes', 'parent strategies'] },
    { stageKey: 'born_month_20', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Language Growth and Combining Words', summary: 'Around 20 months, vocabulary grows rapidly and some toddlers begin to combine two words into simple phrases.', content: 'At 20 months, most toddlers have 25 to 50 words and some begin combining two words like "more milk" or "daddy go." This represents a significant leap from single words to early syntax. Expand on your toddler\'s phrases: "More milk? You want more milk in your cup." Read books with repetitive phrases your toddler can join in on. Sing songs with gestures to reinforce meaning. If your toddler is not yet combining words, that is likely still within the typical range — focus on modeling language naturally throughout the day. The single best predictor of language development is the amount of responsive, back-and-forth interaction your toddler experiences.', source: 'DEVELOPMENT' as ContentSource, tags: ['language development', 'word combinations', 'vocabulary growth', 'toddler communication', 'two-word phrases'] },
    { stageKey: 'born_month_20', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Jumping Safety and Fall Prevention', summary: 'As jumping skills emerge, proactive safety measures protect your enthusiastic toddler from preventable injuries.', content: 'The excitement of new jumping ability can lead toddlers to attempt jumps from inappropriate heights — couches, beds, and stairs. While exploration is developmentally appropriate, injuries from falls peak during the toddler years. Place furniture away from windows and ensure window guards are installed on upper floors. Use carpet or foam mats in areas where jumping practice happens. Teach safe jumping: "We jump on the floor" or "We jump on the grass." Supervise actively during this high-risk-for-falls window. If your toddler does fall, assess calmly — your reaction teaches them whether to panic. Know the signs of concussion: vomiting, excessive crying, changes in balance, or unusual sleepiness warrant immediate medical evaluation.', source: 'CLINICAL' as ContentSource, tags: ['jumping safety', 'fall prevention', 'toddler injuries', 'home safety', 'concussion awareness'] },
    { stageKey: 'born_month_21', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'Two-Word Phrases Take Off', summary: 'The emergence of two-word phrases around 21 months marks the beginning of true language.', content: 'By 21 months, many toddlers begin regularly combining words into two-word phrases — a milestone that fundamentally changes communication. Your toddler can now express desires like "more cookie," describe actions like "daddy go," and comment on their world like "big truck." This explosion reflects growing vocabulary, working memory, and the cognitive ability to understand relationships between words. Respond enthusiastically to all communication attempts. If your toddler is not yet combining words, continue providing rich language input and mention it at your next pediatric visit. Bilingual toddlers may combine words across languages — this is a sign of sophisticated language processing, not confusion.', source: 'DEVELOPMENT' as ContentSource, tags: ['two-word phrases', 'language milestone', 'expressive language', 'toddler communication', 'language development'] },
    { stageKey: 'born_month_21', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 86, title: 'Imaginary Play Expands in Complexity', summary: 'Around 21 months, pretend play becomes richer and more elaborate, reflecting cognitive and social-emotional growth.', content: 'Imaginary play takes a noticeable leap around 21 months. Your toddler may now act out simple scenarios — feeding a doll, putting a stuffed animal to bed, or pretending to cook. Provide simple props that support open-ended play: dolls, stuffed animals, play food, blankets, and boxes. A cardboard box can become anything — a car, a house, a bed — and the open-ended nature supports creativity more than single-purpose electronic toys. Join your toddler\'s play when invited but let them lead. Resist the urge to make play educational; the learning happens naturally through imagination. Pretend play also helps toddlers process emotions and experiences.', source: 'DEVELOPMENT' as ContentSource, tags: ['imaginary play', 'pretend play', 'creative play', 'toddler imagination', 'symbolic thinking'] },
    { stageKey: 'born_month_21', category: 'SLEEP' as AdviceCategory, priority: 89, title: 'Nighttime Fears and Bedtime Comfort', summary: 'Around 21 months, new nighttime fears can emerge as imagination develops and the world becomes more complex.', content: 'As imagination blossoms, so can fears of the dark, monsters, or being alone. This is a cognitive milestone — your toddler can now imagine things that are not present, including scary things. Validate feelings without reinforcing fears: "I understand you feel scared. You are safe in your bed." A consistent, calming bedtime routine becomes even more important. A nightlight, a special stuffed animal "protector," or "monster spray" in a spray bottle can offer concrete comfort. Check under the bed together and declare the room safe. Avoid scary media — even content that seems benign to adults can be frightening to a toddler\'s developing mind. These fears are typically transient but deserve respect and gentle reassurance.', source: 'DEVELOPMENT' as ContentSource, tags: ['nighttime fears', 'bedtime anxiety', 'toddler imagination', 'sleep comfort', 'emotional security'] },
    { stageKey: 'born_month_21', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Following Two-Step Commands', summary: 'Following two-step directions represents a cognitive leap in working memory, sequencing, and receptive language.', content: 'Around 21 months, many toddlers can follow two-step related commands like "Pick up the book and give it to me." This requires holding two pieces of information in mind and executing them in sequence — a complex cognitive task. Practice with fun, routine-based directions: "Get your shoes and bring them here." Pair words with gestures to support comprehension. If your toddler struggles, break the direction into single steps, then gradually reintroduce two-step sequences. Celebrate success warmly. Difficulty following two-step commands consistently at this age is still within the typical range, but persistent difficulty understanding simple language warrants discussion with your pediatrician.', source: 'DEVELOPMENT' as ContentSource, tags: ['following directions', 'two-step commands', 'receptive language', 'working memory', 'cognitive development'] },
    { stageKey: 'born_month_21', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 83, title: 'Expanding Your Toddler\'s Food Repertoire', summary: 'Gentle strategies can gradually expand the foods your toddler accepts within the Division of Responsibility framework.', content: 'Even with the Division of Responsibility firmly in place, parents often worry when their toddler\'s accepted foods list shrinks. To gently expand variety, offer one new or less-preferred food alongside two accepted foods at a meal. Exposure without pressure is key — research shows it can take 10 to 15 neutral exposures before a toddler accepts a new food. Let your toddler see you enjoying the food without comment. Involve your toddler in simple food preparation: washing vegetables, stirring, or placing items on a plate. Gardening, even a windowsill herb pot, can increase willingness to try new foods. Maintain perspective: nutritional adequacy is measured over a week, not a single meal.', source: 'DEVELOPMENT' as ContentSource, tags: ['food variety', 'picky eating', 'food exposure', 'toddler nutrition', 'feeding strategies'] },
    { stageKey: 'born_month_21', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'Managing Your Toddler\'s Big Emotions', summary: 'Your toddler\'s emotional intensity can be draining; understanding the developmental reasons helps you stay grounded.', content: 'The emotional highs and lows of a 21-month-old are intense — joy, frustration, anger, and affection all expressed with full-body intensity. This emotional roller coaster reflects an immature prefrontal cortex that cannot yet regulate the powerful limbic system. Your job is not to stop the feelings but to lend your calm nervous system as a model for regulation. When you feel yourself getting pulled into the emotional storm, ground yourself: feet on the floor, a deep breath, a silent reminder that this is developmentally appropriate. Protect your own emotional reserves with adequate sleep, nutrition, and social support. Seek support from a partner, family member, or professional if you are consistently overwhelmed.', source: 'DEVELOPMENT' as ContentSource, tags: ['emotional regulation', 'toddler emotions', 'parent wellbeing', 'co-regulation', 'parental resilience'] },
    { stageKey: 'born_month_22', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'Empathy\'s First Signs', summary: 'The earliest signs of empathy emerge around 22 months as your toddler begins to recognize and respond to others\' feelings.', content: 'Around 22 months, toddlers may show the first glimmers of empathy — offering a toy to a crying peer, patting someone who is sad, or looking concerned when someone is hurt. This reflects growing emotional awareness and the beginning of perspective-taking, though it is inconsistent and egocentric concern still dominates. Nurture empathy by naming feelings: "Your friend is sad because she fell down. Let\'s see if she is okay." Model caring responses to others\' distress. Read books about feelings and discuss how characters might feel. Do not force apologies — a scripted "sorry" without genuine feeling teaches compliance, not empathy. Instead, focus on helping your toddler notice the impact of their actions and offering genuine repair.', source: 'DEVELOPMENT' as ContentSource, tags: ['empathy development', 'emotional intelligence', 'social development', 'perspective taking', 'toddler social skills'] },
    { stageKey: 'born_month_22', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 83, title: 'Dressing Skills Through Play', summary: 'Using play to practice dressing builds the fine motor skills and confidence needed for self-care independence.', content: 'By 22 months, many toddlers can remove simple clothing items and are beginning to help with putting clothes on. Turn dressing practice into play with dressing dolls, busy boards featuring zippers and buttons, and dress-up clothes with simple fasteners. Large buttons, chunky zippers, and Velcro closures are easier to manipulate. Practice during calm moments rather than rushed morning departures. Allow your toddler to attempt dressing even when it takes longer — the learning happens in the attempt. Lay out clothes in the order they go on the body to support sequencing. Celebrate partial successes: "You got your arm through the sleeve all by yourself!"', source: 'DEVELOPMENT' as ContentSource, tags: ['dressing skills', 'self-care', 'fine motor development', 'toddler independence', 'play-based learning'] },
    { stageKey: 'born_month_22', category: 'DEVELOPMENT' as AdviceCategory, priority: 92, title: 'Limit Testing and Setting Consistent Boundaries', summary: 'Limit testing peaks as your toddler approaches age two; understanding its purpose helps you respond with consistency and empathy.', content: 'Limit testing — the "what happens if I..." experiments — intensifies around 22 months as your toddler explores cause and effect in the social world. This behavior is driven by curiosity and cognitive development, not defiance. When limits are tested, respond calmly and consistently without lengthy explanations. Use simple, firm language: "The answer is no. We do not throw food." Follow through every time — intermittent reinforcement makes limit testing more persistent. Save your firm limits for health, safety, and family values; let go of battles that do not matter. Remember that your toddler needs to test limits to internalize them. Your consistent, kind boundaries are literally building their understanding of how the world works.', source: 'DEVELOPMENT' as ContentSource, tags: ['limit testing', 'boundaries', 'toddler discipline', 'consistent parenting', 'behavior guidance'] },
    { stageKey: 'born_month_22', category: 'SLEEP' as AdviceCategory, priority: 88, title: 'Consistent Routines for Limit-Testing Toddlers', summary: 'When bedtime becomes a battleground of limit-testing, consistency in your routine is your most powerful tool.', content: 'Limit testing at 22 months frequently targets bedtime — one more book, one more drink, one more trip to the bathroom. Your toddler is not manipulating you; they are learning about boundaries at a time when separation also triggers genuine anxiety. Create a visual bedtime routine chart with simple pictures showing each step. Use a timer or a countdown: "Two more minutes of play, then bath time." Be boringly consistent with your responses to stalling — the same calm phrase every time: "It is sleep time now. I love you." Avoid introducing new elements to the routine during limit-testing phases. A predictable bedtime order reduces anxiety and gives your toddler fewer openings for negotiation.', source: 'DEVELOPMENT' as ContentSource, tags: ['bedtime stalling', 'sleep routines', 'limit testing', 'consistent parenting', 'toddler sleep'] },
    { stageKey: 'born_month_22', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 87, title: 'Stair Safety as Skills Advance', summary: 'As your toddler becomes more confident on stairs, supervision remains essential even as skills improve.', content: 'By 22 months, many toddlers attempt to walk down stairs with help rather than crawling backward. This is an exciting advancement but also a higher-risk period as confidence may outpace competence. Continue to supervise all stair use, even as your toddler protests for independence. Teach and model holding the railing with one hand while holding your hand with the other. Consider installing a second, lower handrail if your staircase allows. Non-slip treads on wooden stairs provide additional traction. If your toddler insists on independence, stay one step below them as a spotter. Falls down stairs are a leading cause of toddler emergency visits — continued vigilance is essential.', source: 'CLINICAL' as ContentSource, tags: ['stair safety', 'toddler falls', 'home safety', 'injury prevention', 'gross motor safety'] },
    { stageKey: 'born_month_22', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 86, title: 'Self-Compassion Through Challenging Phases', summary: 'When parenting feels particularly hard, self-compassion protects your mental health and your relationship with your child.', content: 'The limit-testing, emotional intensity, and physical demands of a 22-month-old can leave parents depleted and doubting themselves. Self-compassion — treating yourself with the kindness you would offer a friend — is not self-indulgence; it is a research-backed strategy for resilience. When you lose your patience, acknowledge it without shame: "That was a hard moment. I am a good parent having a hard time." The goal is not perfect parenting but repair after rupture. Your child learns from watching you recover from mistakes. Connect with other parents who can normalize this challenging phase. If self-criticism is constant, reaching out to a therapist or your healthcare provider is a sign of strength.', source: 'DEVELOPMENT' as ContentSource, tags: ['self-compassion', 'parent wellbeing', 'parental mental health', 'challenging phases', 'parental resilience'] },
    { stageKey: 'born_month_23', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'Three-Word Sentences and Language Flourishing', summary: 'Three-word sentences emerge around 23 months, giving your toddler a powerful new way to express thoughts and needs.', content: 'By 23 months, many toddlers begin combining three or more words: "I want juice," "daddy go work," or "more book please." This represents a leap in grammatical understanding as your toddler begins to grasp sentence structure. Celebrate and expand their sentences: "You want more apple juice? Let\'s pour some together." Continue reading daily, asking simple questions about the story to build comprehension. Narrate your activities and ask open-ended questions that invite more than yes-or-no responses. The range of typical language development is wide, and bursts of progress often follow quieter periods.', source: 'DEVELOPMENT' as ContentSource, tags: ['three-word sentences', 'language development', 'expressive language', 'toddler communication', 'grammar development'] },
    { stageKey: 'born_month_23', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 86, title: 'Turn-Taking Games for Social Growth', summary: 'Simple turn-taking games at 23 months build the social skills that support friendships and cooperative play.', content: 'Turn-taking is an emerging skill at 23 months — your toddler may understand the concept but struggle with the patience required. Practice with simple games: rolling a ball back and forth, taking turns stacking blocks, or using a visual timer for shared toys. Keep turns very short — 30 seconds to one minute — to match your toddler\'s developing patience. Narrate the process: "My turn... now your turn!" Celebrate when your toddler waits or shares spontaneously. Do not expect consistent turn-taking; this skill develops gradually through early childhood. Playdates at this age still require close adult support to scaffold turn-taking and manage conflicts.', source: 'DEVELOPMENT' as ContentSource, tags: ['turn-taking', 'social skills', 'toddler play', 'sharing', 'cooperative play'] },
    { stageKey: 'born_month_23', category: 'DEVELOPMENT' as AdviceCategory, priority: 93, title: 'Emotion Coaching Your Toddler', summary: 'Emotion coaching — naming, validating, and guiding your toddler through feelings — builds lifelong emotional intelligence.', content: 'Emotion coaching is a research-backed approach that involves noticing emotions, viewing them as opportunities for connection, validating feelings, and helping your child label them. When your toddler is upset, get down to their level and name what you see: "You are really frustrated the blocks fell down." Validation does not mean agreement — you can validate the feeling without endorsing the behavior: "It is okay to be angry. It is not okay to throw blocks." Over time, your toddler internalizes this process and begins to self-regulate. Children who receive emotion coaching show better emotional regulation, social skills, and even academic outcomes later.', source: 'DEVELOPMENT' as ContentSource, tags: ['emotion coaching', 'emotional intelligence', 'toddler emotions', 'validating feelings', 'parenting approach'] },
    { stageKey: 'born_month_23', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 82, title: 'Involving Toddlers in Food Preparation', summary: 'Simple kitchen involvement builds food familiarity, fine motor skills, and a sense of competence.', content: 'At 23 months, your toddler can participate in simple food preparation tasks with close supervision. Washing vegetables, tearing lettuce, stirring batter, sprinkling cheese, and placing toppings all offer meaningful participation. Use a stable learning tower or step stool at the counter for safe access. Expect mess and build in extra time. The goal is not efficient cooking but relationship-building and food exposure. Toddlers are often more willing to taste foods they helped prepare. Keep safety paramount: no handling of knives, hot surfaces, or raw meat. This early kitchen involvement lays groundwork for later cooking skills.', source: 'DEVELOPMENT' as ContentSource, tags: ['kitchen involvement', 'food preparation', 'toddler activities', 'food exposure', 'fine motor practice'] },
    { stageKey: 'born_month_23', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 85, title: 'Tiptoe Walking and Foot Development', summary: 'Walking on tiptoes is a common milestone around 23 months that supports foot strength and balance development.', content: 'Around 23 months, many toddlers discover they can stand and walk on tiptoes. This skill requires significant calf strength, balance, and body awareness. Occasional tiptoe walking during play is normal and beneficial for foot muscle development. However, persistent tiptoe walking — where your toddler walks on toes most of the time — warrants discussion with your pediatrician, as it can sometimes indicate tight heel cords or sensory processing differences. Encourage flat-footed walking through activities like walking on different surfaces, squatting to play, and wearing supportive but flexible shoes. Most intermittent tiptoe walking resolves on its own as part of typical motor exploration.', source: 'CLINICAL' as ContentSource, tags: ['tiptoe walking', 'foot development', 'gross motor', 'toddler milestones', 'motor development'] },
    { stageKey: 'born_month_23', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 88, title: 'Preparing Yourself for the Twos', summary: 'The approach of your child\'s second birthday is a natural time to reflect on your parenting journey.', content: 'As your toddler approaches age two, you may feel a mix of excitement and apprehension about the legendary "terrible twos." Reframe this phase: twos are not terrible but transformative. Your child is becoming a more capable, communicative, and independent person — and that transition brings bumps. Reflect on the strategies that have worked for you so far and identify areas where you would like more support. Consider parenting books, podcasts, or groups focused on the two-to-three-year-old phase. Strengthen your partnership with your co-parent by discussing values and approaches now. Most of all, trust that the same intuition and love that brought you through the first two years will carry you through the next.', source: 'DEVELOPMENT' as ContentSource, tags: ['preparing for twos', 'parent reflection', 'toddler phase', 'parental confidence', 'looking ahead'] },
    { stageKey: 'born_month_24', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 97, title: 'The 2-Year Checkup and Vaccines', summary: 'The 2-year well-child visit is a comprehensive health milestone that includes important immunizations and developmental assessment.', content: 'The 2-year checkup is a major health milestone. Your pediatrician will assess growth, development, nutrition, sleep, and behavior while addressing any concerns you have about the toddler period. This visit typically includes important immunizations. Prepare a list of questions in advance — about speech milestones, behavior, nutrition, or sleep patterns. Your pediatrician may screen for lead exposure and anemia depending on risk factors. This is also an ideal time to discuss toilet learning progress, dental visits, and screen time guidelines. Be honest about challenges; your pediatrician is your partner in your child\'s health.', source: 'CLINICAL' as ContentSource, tags: ['2 year checkup', 'well-child visit', 'immunizations', 'developmental assessment', 'toddler health'] },
    { stageKey: 'born_month_24', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'From Parallel to Associative Play', summary: 'Around age two, play with peers begins shifting from side-by-side play toward brief interactions and shared activities.', content: 'At 24 months, most toddlers engage primarily in parallel play — playing near peers but not with them. However, the first signs of associative play emerge: brief interactions, imitating each other\'s actions, and occasionally engaging in the same activity together. This shift is gradual and inconsistent; expect parallel play to remain the dominant mode for many months. Support this transition by providing multiples of popular toys to reduce conflict. Keep playdates short — 45 to 60 minutes is plenty. Your close presence provides the security your toddler needs to venture into social interaction. Do not expect sharing or cooperative play yet; those skills develop through the preschool years.', source: 'DEVELOPMENT' as ContentSource, tags: ['associative play', 'parallel play', 'peer interaction', 'social development', 'play development'] },
    { stageKey: 'born_month_24', category: 'DEVELOPMENT' as AdviceCategory, priority: 92, title: 'The 100-Word Milestone and Beyond', summary: 'Reaching 100 to 200-plus words around age two transforms communication and opens new worlds of expression.', content: 'By 24 months, most toddlers have a vocabulary of 100 to 200-plus words, with some reaching far higher. Your toddler can now communicate wants, observations, and feelings with increasing precision. They understand far more than they can produce — receptive vocabulary may be many hundreds of words. Continue reading aloud daily, asking questions that promote thinking, and engaging in rich conversation throughout the day. Limit passive screen time, which does not support language development the way responsive interaction does. If your toddler has fewer than 50 words or is not combining words by 24 months, discuss with your pediatrician. Speech and language delays are common and early intervention is highly effective.', source: 'DEVELOPMENT' as ContentSource, tags: ['vocabulary milestone', '100 words', 'language development', 'expressive language', 'toddler communication'] },
    { stageKey: 'born_month_24', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Running Games and Outdoor Adventures', summary: 'Smooth, confident running at 24 months opens up a world of active outdoor play and physical challenges.', content: 'By 24 months, most toddlers run smoothly with fewer falls and can navigate obstacles with increasing skill. Outdoor play offers the ideal context for practicing these emerging abilities. Create simple running games: chase bubbles, run to a tree and back, or follow-the-leader with simple movements. Playground visits now offer more possibilities — slides, climbers, and open fields for running. Outdoor time also provides sensory richness and supports healthy sleep through physical activity and daylight exposure. Aim for at least 60 minutes of active play daily. Dress for the weather and get outside in most conditions.', source: 'DEVELOPMENT' as ContentSource, tags: ['running', 'outdoor play', 'physical activity', 'gross motor', 'active lifestyle'] },
    { stageKey: 'born_month_24', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 85, title: 'Feeding Your Growing Almost-Two-Year-Old', summary: 'As your toddler approaches age two, their nutritional needs and eating patterns continue to evolve.', content: 'A two-year-old\'s nutritional needs support continued growth, brain development, and increasingly high activity levels. Offer three meals and two to three snacks at predictable times, allowing your toddler to decide what and how much to eat from what you provide. Include foods from all food groups over the course of the day rather than expecting balance at every meal. Iron-rich foods remain important as iron stores from birth are depleted. Continue to offer whole milk or appropriate dairy alternatives unless your pediatrician recommends otherwise. Limit juice and sugary drinks. Model enjoyment of a varied diet — your toddler watches what you eat far more than they listen to what you say about food.', source: 'DEVELOPMENT' as ContentSource, tags: ['toddler nutrition', 'healthy eating', 'meal planning', 'feeding guidelines', 'two-year-old diet'] },
    { stageKey: 'born_month_24', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 89, title: 'The Dance of Independence and Connection', summary: 'The central tension of toddlerhood — push for independence, pull for connection — shapes your relationship and your child\'s development.', content: 'The toddler\'s dual drive — "I can do it myself" alongside "don\'t leave me" — is not inconsistency; it is the core developmental task of the second year. Your toddler is building autonomy within the safety of your relationship. Support both needs: offer opportunities for independence during calm moments like choosing clothes or helping with tasks, and provide abundant connection during transitions and stressful times. When your toddler pushes you away and then cries for you, they are not being manipulative; they are practicing the separation and reunion that builds secure attachment. Your steady presence through this push-pull teaches your child that they can explore the world and always return to you.', source: 'DEVELOPMENT' as ContentSource, tags: ['independence connection', 'secure attachment', 'toddler development', 'parenting relationship', 'autonomy support'] },
  ];
  for (const card of cards) {
    await prisma.expertAdviceCard.upsert({
      where: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}` },
      update: card, create: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}`, ...card },
    });
  }
  console.log(`Seeded ${cards.length} toddler advice cards (months 13-24)`);
}
